import React from 'react';
import styled from "styled-components";

const Background = styled.div`
  height: 100vh;
  background-position: center;
  background-color: #151719;
`;

const Appname = styled.div`
  font-size: 5vh;
  margin: 0;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: aliceblue;
  text-align: center;


`;


// Testing background
function Home() {
    return (
        <Background>
            <Appname>
                Climate Watch
            </Appname>
        </Background>
    );
}

export default Home;
